<template><div><div class="config-head"><div><h3>Configuration Center</h3><p>版本化管理环境变量、ConfigMap、Secret 与运行资源</p></div><div><el-select v-model="environmentId" style="width:145px"><el-option v-for="env in environments" :key="env.id" :label="env.display_name||env.environment_name" :value="env.id"/></el-select><el-button type="primary" :disabled="!environmentId" @click="openCreate">＋ 添加配置</el-button></div></div><el-tabs v-model="type"><el-tab-pane v-for="tab in tabs" :key="tab.value" :label="tab.label" :name="tab.value"/></el-tabs><section class="surface config-table"><div class="surface-header"><div><h3>{{activeLabel}}</h3><p>{{descriptions[type]}}</p></div><span>{{configs.length}} items</span></div><el-skeleton :loading="loading" animated :rows="5"><el-table v-if="configs.length" :data="configs"><el-table-column label="Key" min-width="200"><template #default="{row}"><code>{{row.config_key}}</code><span v-if="row.is_secret" class="secret">Encrypted</span></template></el-table-column><el-table-column label="Value" min-width="280"><template #default="{row}"><span class="value" :class="{masked:row.is_secret}">{{row.value}}</span></template></el-table-column><el-table-column label="Version" width="90"><template #default="{row}">v{{row.version}}</template></el-table-column><el-table-column label="Changed by" prop="changed_by" width="120"/><el-table-column label="Updated" width="160"><template #default="{row}">{{format(row.created_at)}}</template></el-table-column><el-table-column label="操作" width="130"><template #default="{row}"><el-button link @click="edit(row)">编辑</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><EmptyState v-else title="该环境暂无配置" description="添加第一条配置，所有变更都会保留历史版本。"/></el-skeleton></section><div class="redeploy surface"><div><span>↻</span><div><b>配置变更尚未应用？</b><p>保存配置后重新部署应用，使最新配置进入 Kubernetes 工作负载。</p></div></div><el-button :loading="redeploying" @click="redeploy">重新部署</el-button></div><el-dialog v-model="dialog" :title="editing?'编辑配置':'添加配置'" width="560px"><el-form label-position="top"><el-form-item label="配置类型"><el-select v-model="form.config_type" :disabled="!!editing"><el-option v-for="tab in tabs" :key="tab.value" :label="tab.label" :value="tab.value"/></el-select></el-form-item><el-form-item label="Key"><el-input v-model="form.config_key" :disabled="!!editing" placeholder="DATABASE_URL"/></el-form-item><el-form-item label="Value"><el-input v-model="form.value" type="textarea" :rows="7" :placeholder="form.config_type==='secret'?'输入新密文值':'输入配置值'"/></el-form-item><el-form-item label="变更说明"><el-input v-model="form.change_message" placeholder="说明本次变更原因"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="saving" @click="save">保存新版本</el-button></template></el-dialog></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref,watch}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{applicationApi}from'../../api/application';import type{ApplicationConfig,ApplicationEnvironment}from'../../types';import EmptyState from'../common/EmptyState.vue';const p=defineProps<{applicationId:number}>(),environments=ref<ApplicationEnvironment[]>([]),environmentId=ref(0),configs=ref<ApplicationConfig[]>([]),loading=ref(false),saving=ref(false),redeploying=ref(false),dialog=ref(false),editing=ref<ApplicationConfig>(),type=ref('env'),tabs=[{label:'Environment Variables',value:'env'},{label:'ConfigMap',value:'configmap'},{label:'Secret',value:'secret'},{label:'Resources',value:'resource'},{label:'Ingress',value:'ingress'}],descriptions:Record<string,string>={env:'应用容器环境变量',configmap:'非敏感 Kubernetes 配置',secret:'加密存储的敏感信息',resource:'CPU、Memory、Replica 与 Storage',ingress:'域名与流量入口配置'};const form=reactive({config_type:'env',config_key:'',value:'',change_message:''});const activeLabel=computed(()=>tabs.find(t=>t.value===type.value)?.label);async function init(){environments.value=await applicationApi.environments(p.applicationId);environmentId.value=environments.value[0]?.id||0;load()}async function load(){if(!environmentId.value)return;loading.value=true;try{configs.value=await applicationApi.configs(p.applicationId,environmentId.value,type.value)}finally{loading.value=false}}function openCreate(){editing.value=undefined;Object.assign(form,{config_type:type.value,config_key:'',value:'',change_message:''});dialog.value=true}function edit(item:ApplicationConfig){editing.value=item;Object.assign(form,{config_type:item.config_type,config_key:item.config_key,value:item.is_secret?'':item.value,change_message:''});dialog.value=true}async function save(){if(!form.config_key)return ElMessage.warning('请输入配置 Key');saving.value=true;try{if(editing.value)await applicationApi.updateConfig(editing.value.id,{value:form.value,change_message:form.change_message});else await applicationApi.saveConfig(p.applicationId,{...form,environment_id:environmentId.value});ElMessage.success('配置新版本已保存');dialog.value=false;load()}finally{saving.value=false}}async function remove(item:ApplicationConfig){await ElMessageBox.confirm(`确认删除 ${item.config_key}？历史版本仍会保留。`,'删除配置',{type:'warning'});await applicationApi.deleteConfig(item.id);ElMessage.success('配置已删除');load()}async function redeploy(){redeploying.value=true;try{const env=environments.value.find(e=>e.id===environmentId.value);const result=await applicationApi.deploy(p.applicationId,{environment:env?.environment_name});ElMessage.success(result.approval_required?'生产发布审批已提交':'重新部署已启动')}finally{redeploying.value=false}}const format=(v:string)=>new Date(v).toLocaleString('zh-CN',{hour12:false});watch([environmentId,type],load);onMounted(init)

</script>
<style scoped>.config-head{display:flex;justify-content:space-between;align-items:end;margin-bottom:13px}.config-head h3{font-size:14px;margin:0 0 5px}.config-head p{font-size:13px;color:var(--muted);margin:0}.config-head>div:last-child{display:flex;gap:8px}.config-table{overflow:hidden}.surface-header>span{font-size:12px;color:var(--muted)}code{font-size:13px;color:#aab3c2}.secret{margin-left:8px;padding:3px 6px;border-radius:4px;background:rgba(230,169,80,.1);color:#ddab62;font-size:13px}.value{color:#aeb8c7;font:12px "SFMono-Regular",Consolas,monospace}.value.masked{letter-spacing:2px}.redeploy{margin-top:13px;min-height:65px;padding:12px 15px;display:flex;align-items:center;justify-content:space-between;box-shadow:none}.redeploy>div{display:flex;align-items:center;gap:11px}.redeploy>div>span{width:31px;height:31px;display:grid;place-items:center;border-radius:8px;background:var(--primary-soft);color:#9387ec}.redeploy b,.redeploy p{display:block}.redeploy b{font-size:13px}.redeploy p{font-size:12px;color:var(--muted);margin:4px 0 0}</style>
